export function getTechLogo(name: string): React.ElementType {
  const lower = name.toLowerCase();
  
  // Specific matchers
  if (lower.includes("postgres")) return PostgresLogo;
  if (lower.includes("nginx")) return NginxLogo;
  if (lower.includes("yugabyte")) return YugabyteLogo;
  if (lower.includes("aerospike")) return AerospikeLogo;
  if (lower.includes("jenkins")) return JenkinsLogo;
  
  // Cloud / general matching
  if (lower.includes("sql")) return SqlLogo;
  if (lower.includes("pubsub") || lower.includes("pub-sub") || lower.includes("pub/sub")) return PubSubLogo;
  if (lower.includes("storage") || lower.includes("bucket")) return CloudStorageLogo;

  // Fallbacks
  if (lower.includes("database") || lower.includes("db")) return Database;
  return Server;
}
